import{_ as e,o as p,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"假面骑士空我","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/1.生理类/假面骑士空我.md","filePath":"4.资源分区/2.改造与功法/改造/1.生理类/假面骑士空我.md"}'),o={name:"4.资源分区/2.改造与功法/改造/1.生理类/假面骑士空我.md"};function s(d,b,_,l,i,c){return p(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"假面骑士空我",tabindex:"-1"},[t("假面骑士空我 "),r("a",{class:"header-anchor",href:"#假面骑士空我","aria-label":'Permalink to "假面骑士空我"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),n('<h1 id="假面骑士空我-1" tabindex="-1">假面骑士空我 <a class="header-anchor" href="#假面骑士空我-1" aria-label="Permalink to &quot;假面骑士空我&quot;">​</a></h1><p>假面骑士·空我<br> 描述：出自日本特摄作品《假面骑士》系列中的骑士，作为其中较为特殊的个体，空我适用于大部分的影片场景，擅长各类各类战斗环节。兑换空我能力之后将会与灵石·亚玛达姆融合，灵石可以汲取使用者的精神意志从而完成激活，随使用者的思考从而完成变身效果。<br> 由亚玛达姆放出的类似神经状的物质与全身的组织融合，并且在接受了神经组织般的物质的指令后，身体会在分子、原子水平上产生急剧变化，细胞产生变化从而强化成超人类的肌肉组织，从而爆发出远胜常人的身体力量。<br> 伴随着改造程度的逐渐加深，身体与灵石之间的融合也会渐渐的加深。可以通过吸收电能、生物能等能量进行灵石能量的恢复与提升。主神优化了这一版本的性能，使一些效果得到了相应的强化。</p><p>初生形态<br> 价格：D+600<br> 最为初级原始的能量形态。通过亚玛达姆回馈的能量进行变身之后体表浮现出物质化的白色盔甲。这是用以承载后续力量的基础，也是亚玛达姆灵石的具现化能力展现。在完成该变身之后，可以提升自己的力量、速度、恢复能力等多种身体素质，大幅度的提升跳跃力，提升幅度可达数倍常人的水平。该形态下并不会消耗灵石能量，但是会消耗体能，当使用者的体力不足以支撑变身之后会消失退化，并且一段时间内无法再次使用。<br> 【变身！】：使用一个迅捷动作与1点意志力，你的意志传达给灵石 凭借亚玛达姆持有的粒子操作能力，同时强化肉体生成特殊的身体甲胄，从而变身为假面骑士空我，效果持续一个场景。<br> 如果你已经穿着其他盔甲，这些盔甲将融入体内，与变身带来的天生防御叠加计算，使盔甲防御永久性转为天生防御进行处理（这意味着你可以正常穿戴盔甲，也可以正常使用武器）。<br> 变身形态可以获得以下效果：<br> 1.获得4点天生防御，具有【防弹】特性，<br> 2.天生武器的伤害提升至3L。<br> 3.具有【快速医疗1】，医疗点数12点。</p><p>【灵石能量】：由亚玛达姆将变身者的意志具现化而成的能量。虽然也有封印能源的称呼，但归根结底还是灵石产生的能量，在性质上也有直接渗透防御，通过固体或气体传播的用法。<br> 灵石能量的大小相当于【决心】+【耐力】属性，恢复方式是每小时自动恢复【关键属性取高】/6点。<br> 你也可以通过休息的方式加速能量恢复，在一次短休息后进行关键属性检定，恢复等同成功数的灵石能量，灵石能量一日的恢复上限为能量池上限的三倍。<br> 【开启灵石能量池的价格是500分，已经购买了假面骑士空我则需要支付2XP来适应灵石能量，否则不仅无法运用这一能量池，还会默认占据一项能量池的位置。】</p><p>元素形态（全能形态）<br> 价格：C+1200<br> 地-泰坦、火-全能、风-天马、水-青龙。代表四元素的力量融入亚玛达姆之中，从而焕发出全新的姿态。来源于主神兑换的缘故，并不需要有强烈的战斗意志才能完成变身。<br> 每一次的兑换可以使亚玛达姆获得一种全新的元素状态并且扩充灵石能量，每一种状态均有自己的特色之处，但都是远胜于初始形态的力量。如均衡提高的火、侧重速度与反应的水、专注感知与应对的水、特化耐力和力量的地。本阶段提供的全能形态作为前置，之后才能兑换青龙、天马、泰坦三种形态。<br> 特殊的，尽管未曾掌握，但亚玛达姆的具现化能力已经开始有所体现，在获得对应形态的变身之后能够将对应形态的武器展现，进行具现化。<br> 【全能形态】：使用一个迅捷动作与6点灵石能量，你的意志传达给灵石，凭借亚玛达姆持有的粒子操作能力，同时强化肉体生成特殊的身体甲胄，从而变身为全能形态，效果持续一个场景。<br> 如果你已经穿着其他盔甲，这些盔甲将融入体内，与变身带来的天生防御叠加计算，使盔甲防御永久性转为天生防御进行处理（这意味着你可以正常穿戴盔甲，也可以正常使用武器）。<br> ——<br> 全能形态可以获得以下效果：<br> 1.获得等同自身【耐力】属性一半的天生防御，具有【防弹】特性。<br> 2.天生武器的伤害提升至3+【传奇力量*3】L。<br> 3.具有【快速医疗1】，医疗点数12点。<br> 4.在嗅觉，视觉，听觉中选择一项，使其升级为强感知定位能力，但若是选择嗅觉则只能新增嗅觉定位的感知能力。</p><p>金之力（升华全能）<br> 价格：B+2400<br> 描述：融入雷霆，名为金之力的力量后，从未来的究极形态中取得的部分能力所转化的名为升华的姿态。升华姿态会比原有的形态更为强大，所获得的力量也完整，但金之力状态下维持形态所消耗的力量也更加可怕。<br> 效果：<br> 【升华全能】：使用一个迅捷动作与10点灵石能量，你的意志传达给灵石，凭借亚玛达姆持有的粒子操作能力，同时强化肉体生成特殊的身体甲胄，从而变身为升华全能形态，效果持续一个场景。<br> 如果你已经穿着其他盔甲，这些盔甲将融入体内，与变身带来的天生防御叠加计算，使盔甲防御永久性转为天生防御进行处理（这意味着你可以正常穿戴盔甲，也可以正常使用武器）。<br> ——<br> 【升华全能形态】在保留全能形态的基础上，可以获得以下效果：<br> 1.你获得等同自身耐力属性三分之一的全伤害吸收能力，基于天生防御。<br> 2.每轮一次，你在进行攻击时，最终造成的伤害增加一半计算。</p><p>惊异全能<br> 价格：A+4800<br> 描述：升华全能状态下将金之力发挥至极限，触碰「究极」领域后所产生得到的能力。相当于是究极形态的雏形，拥有完整的升华全能腿甲，能够自由控制升华状态，已经摆脱灵石能量本身的限制与约束。是不兑换其他形态下，所能达到的最巅峰状态。<br> 效果：<br> 从现在开始，你无需消费灵石能量也无需消费动作即可变身假面骑士空我，若你已经购买了对应形态，则你可以自行选择变身升华全能，升华青龙，升华天马，或是升华泰坦形态。<br> 即使你不进行变身，也常驻具有这些形态的效果（要求已购买），这意味着你同时享受四种形态带来的额外好处。<br> ——<br> 除此之外，你获得以下效果：<br> 1.每轮开始时，你额外获得8AP，但这8AP只能用于使用下属技能树中的能力（比如结合在其他AP中使用下属技能）。<br> 2.你进行的攻击具有8加骰。<br> 3.你的触及距离提升至等同自身敏感范围，在画面表现上这是你对于微观粒子控制能力的应用/控制能力提升而带来的力量。</p><p>究极形态<br> 价格：暂不开放<br> 前置：全能形态，青龙形态，天马形态，泰坦形态<br> 描述：控制了地火风水的四大元素，融入自身精神意志以后所展现出的绝强姿态。拥有着所有形态的所有力量并获得大幅度强化，能够自由发挥微观粒子控制能力制造出等离子态与火焰，再生能力强到能够在短时间内恢复致命伤势的程度。<br> 效果：-</p><p>————————<br> 【D级专属技能】<br> 强大恢复力<br> 价格：D+1000<br> 分类：被动<br> 效果：亚玛达姆的机能可以使变身者在最致命的伤害中恢复，强大的回复力还能根据本人的意志加速。<br> 效果：血统中提供的快速医疗点数提升2点（这意味着抵达3点的快速医疗能力可以再生肢体），医疗点数扩大24点。</p><p>Compound Eyes(复眼)<br> 价格：D+500<br> 分类：被动<br> 描述：复眼状的眼睛。很多视觉细胞集合，视界及视力都是人类的数十倍。由复眼收集的情报统合后传送到脑部，使雄介能像常人一般感觉地看见物体。另外，表面有守护视觉细胞的坚硬玻璃状物质覆盖，即使被碰到也不会疼痛。<br> 效果：变身状态下，你获得基于视觉的D级自然本质侦测能力。若你的视觉没有被升级为强感知，则将被升级至强感知定位能力，已升级至强感知能力的情况下，则获得一种新建的类【盲视】能力。<br> 你可以选择在购买时将该能力改为【Enhanced Ear(强化耳)】或【Olfactometer(嗅觉计)】，使该能力强化的感官对应改为：听觉，或嗅觉。此时无法因已升级为强感知定位能力获得类【盲视】能力。</p><p>基础强化<br> 价格：D+500<br> 分类：被动<br> 描述：灵石·亚玛达姆的效果是基于身体的改变，随着锻炼开发的身体会逐渐融合，使你在变身前/后都能获得更多的的强化。<br> 效果：你的基础移动速度增加10米，同时获得额外3点天生防御。</p><p>能量强化<br> 价格：D+500<br> 分类：被动<br> 描述：受限于个人素质的缘故，灵石能量本身是有限的，但你可以通过不断锻炼来提升这一极限。<br> 效果：灵石能量池将随着你最高内在支线等级成长，你的灵石能量上限提升等同内在最高支线等级*6点。</p><p>Knee Absorber(膝吸收器)<br> 价格：D+500<br> 分类：被动<br> 描述：Knee Absorber(膝吸收器)可以在剧烈战斗中减轻脚的负担，除了具有大幅度增加跳跃能力的性能外，也可以早跳跃与踢击的冲击中守护骨与筋肉。<br> 效果：变身状态下，你免疫自然坠落伤害，同时可以准确的控制跳跃的落点和距离而无需检定，将跳跃和移动结合起来，但跳跃的高度不能超过移动距离的1/2，回合结束时仍然需要站在稳固的落脚点上，否则就会坠落。<br> ————————<br> 【C级专属技能】<br> 微观粒子操纵（削弱/增强）<br> 价格：C+1000/C+2000<br> 动作：移动动作<br> 距离：见下<br> 目标：见下<br> 消耗：3<br> 持续：一场景<br> 描述：灵石可以将物质在分子、原子水平上分解、重组。虽然你并不能做到将树枝变为自己的武器、或是将空气变为自己身上的盔甲的能力，但简单的增强或是削弱还是能做到的。<br> 效果：购买时，必须选择获得增强或者是削弱能力，你可以通过购买这一能力两次来同时获得增强与削弱能力。场上最多同时存在一项增强与削弱效果。<br> 【削弱】<br> 消费移动动作，你需要自行选择其中一项效果，该效果会在你下次攻击命中后赋予目标。<br> 1.目标盔甲或天生防御降低等同你的传奇决心*5点。若目标的盔甲或天生防已降低至0，则在你攻击目标时，你的攻击检定上获得等同剩余降低数值*1点增强加值。<br> 2.目标获得物理易伤X，X等同于你的传奇决心/点。<br> 【无论如何，同时只会有一个目标承受这一效果。】<br> ——<br> 【增强】<br> 消费移动动作，你指定触及单位内的任一友方单位（包括自身），使目标选择获得以下效果之一。<br> 1.攻击中的破甲数值提升等同自身传奇决心*5点。<br> 2.武器伤害提升等同自身传奇决心*2L。<br> 3.天生防御提升等同自身传奇耐力*2点。<br> 【无论如何，同时只能有一个目标享受这一好处。】</p><p>战斗技巧<br> 价格：C+1000<br> 分类：被动<br> 描述：力量不会自己创新，但你可以通过锻炼来学习如何最大限度的发挥力量。<br> 效果：冲锋时有效距离取最大值计算；冲锋的移动行为结束后，即使对方离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击；当你冲锋时，你的基础防御不承受减值。</p><p>形态转换<br> 价格：D+500<br> 描述：经过了刻苦的锻炼，现在你可以流畅的转换形态。<br> 效果：当你处于全能/青龙/天马/泰坦形态时，你可以使用反射动作立刻切换至另一种形态，这次切换具有打断性，可能会影响到一些效果。</p><p>全能踢<br> 价格：C+1000<br> 动作：整轮动作<br> 目标：单一目标<br> 消耗：4<br> 描述：肌肉异常发达的腿部收束灵石能量，使出飞踢，将能量灌入敌人体内，从而造成更大程度的杀伤。<br> 效果：消耗整轮动作，你进行一次正常的冲锋，本次冲锋攻击检定获得等同自身力量数值的增强加值，具有的加骰提升1级（上限8加骰）。<br> 此外，你可以将其中1点严重伤害转为韧性伤害进行处理。<br> ——<br> 升级（C+1000）：全能踢可以同时对冲锋路径上触及距离内的所有敌对目标造成伤害。<br> 升级（B+2500）：使用全能踢前，你需要进行一次纯运动技能检定，本次检定无法获得任何相关检定加值，只能使用纯技能进行检定。你接下来使用全能踢的冲锋攻击检定中，获得等同上述运动检定成功数的额外附加成功数。</p><p>青龙形态Ⅰ<br> 价格：C+2000<br> 前置：全能形态<br> 持续：一场景<br> 描述：跳跃能力与灵活性方面极高，擅长流水般流畅的战法。古临多文记载为「掌司水之战士」。「逢邪物现，化彼之百技为无形，若流水之姿平复邪恶的战士」<br> 效果：<br> 当你处于全能形态下，你可以使用自由动作转换为青龙形态。青龙形态下，除了具有全能形态的效果外，你还获得以下好处：<br> 1.你进行跳跃移动时，可以额外进行一次跳跃检定，将检定成功数计入移动距离之中，这意味着本次移动距离为【基础移动距离】+【跳跃检定成功数】/米。<br> 2.你的基础移动速度增加【5+传奇敏捷*10】米。<br> 3.你可以将长柄类物品（要求无主）临时化作青龙棍，完全取代原有的效果，这无需动动作。青龙棍会在脱手时自动消失，变身解除后，武器也会自动消失。<br> 当你使用青龙棍时，你依旧采用【武技+拳或腿】代替【武技+棍】进行攻击，可以正常使用棍类武器技艺。<br> 【购买青龙形态不会获得自由属性。】<br> ——<br> 青龙棍<br> 分类：长棍<br> 体积：5<br> 武器基本属性：8L<br> 武器特殊属性：【双手】【长柄武器】【格挡1】<br> 伤害类型：物理-钝击。<br> 若你没有使用武器，则可以将这一武器的伤害计入天生武器伤害中计算。</p><p>青龙形态Ⅱ<br> 价格：C+2000<br> 前置：青龙形态Ⅰ<br> 描述：进一步开发青龙形态的能力，发挥其强化速度与敏捷的性质。<br> 效果：你在青龙形态下，敏捷检定上获得等同自身传奇敏捷*2DP增强加值，在基础移动速度上获得等同自身传奇敏捷*10米的提升。</p><p>天马形态<br> 价格：C+1000<br> 前置：全能形态<br> 持续：一场景<br> 描述：全身神经到达极限的紧张，强化了六感的特殊形态，甚至能看得到红外线、紫外线、电磁波，判断力、洞察力、集中力变得优秀，拥有强韧的精神力，古临多文记载为「掌司风之战士」。「逢邪物现，知彼之形更胜彼身，如疾风之态射穿邪恶的战士」<br> 效果：<br> 当你处于全能形态下，你可以使用自由动作转换为天马形态。天马形态下，除了具有全能形态的效果外，你还获得以下好处：<br> 1.若你已具有【Compound Eyes(复眼)】的能力，则该能力侦测等级提升至C级。<br> 2.你手中的实弹远程武器（包括但不限于枪械，弹弓，玩具枪）将会化作天马弩，完全取代原有的效果，这无需动动作。天马弩会在脱手时自动消失，变身解除后，武器也会自动消失。<br> 当你使用天马弩时，你依旧采用【武技+拳或腿】代替【射击+弩】进行攻击，可以正常使用弓弩武器技艺。<br> 【购买天马形态不会获得自由属性。】<br> ——<br> 天马弩<br> 分类：弩<br> 体积：3<br> 武器基本属性：武器伤害11L<br> 武器特殊属性：【高速3】【破甲1】【双手】【无限弹药】<br> 武器射程：30<br> 伤害类型：物理-穿刺。</p><p>天马形态Ⅱ<br> 价格：C+1000<br> 前置：天马形态Ⅰ<br> 描述：进一步开发天马形态的能力，发挥其强化感知与反应的性质。<br> 效果：你在天马形态下，获得B级措手不及的免疫能力。同时，你可以指定自身一种感知方式的侦测范围+1倍计算，但必须是复眼/强化耳/嗅觉计其中之一的感知方式。</p><p>泰坦形态<br> 价格：C+1500<br> 前置：全能形态<br> 持续：一场景<br> 描述：强化了全身的肌肉和装甲的特殊形态，力量与攻击力、防御力都非常优秀。因为其铁壁般优秀的防御力，对强力敌人的攻击作紧急回避时会变成此形态。古临多文记载为「掌司地之战士」。「逢邪物现，即着以钢铁之盔甲，以破地之势斩断邪恶的战士」<br> 效果：当你处于全能形态下，你可以使用自由动作转换为泰坦形态。泰坦形态下，除了具有全能形态的效果外，你还获得以下好处：<br> 1.你在全能状态中获得的天生防御提升至等同自身【耐力】的数值，而并非一半。<br> 2.你获得免疫接触攻击的效果。<br> 3.你手中伤害类型为穿刺或挥砍的武器将会化作泰坦剑，完全取代原有的效果，这无需动动作。泰坦剑会在脱手时自动消失，变身解除后，武器也会自动消失。<br> 当你使用泰坦剑时，你依旧采用【武技+拳或腿】代替【武技+剑】进行攻击，可以正常使用剑武器技艺。<br> 【购买泰坦形态不会获得自由属性。】<br> ——<br> 泰坦剑<br> 分类：重剑<br> 体积：4<br> 武器基本属性：武器伤害8L<br> 武器特殊属性：【重型武器】【双手】<br> 伤害类型：物理-挥砍。<br> 若你没有使用武器，则可以将这一武器的伤害计入天生武器伤害中计算。</p><p>泰坦形态Ⅱ<br> 价格：C+1500<br> 前置：泰坦形态Ⅰ<br> 描述：进一步开发泰坦形态的能力，发挥其强化力量与耐力的性质。<br> 效果：你在泰坦形态下，力量上获得等同自身传奇耐力*2DP增强加值，同时获得这一数值两倍的强韧豁免检定加值。此外，你获得基于天生防御的【防能量武器】特性。</p><p>————————<br> 【B级专属技能】<br> 升华全能踢<br> 前提：全能踢（逐级）<br> 价格：B+2500<br> 描述：附加了金之力而得到强化，其封印能源极其强大，并有着与之前完全不同的破坏力。主神提供的版本不会引发灾害范围波及半径3KM内的爆炸，但保留了其敌我不分的二次杀伤性能。<br> 效果：你可以将全能踢的能量消耗提升至10点，在全能踢造成伤害后后，立刻再对以自身为中心，除自身以外【30+传奇力量*20】米范围内的所有目标造成一次攻击，敌我不分，这次攻击具有全能踢相关的一切效果。</p><p>升华青龙形态<br> 前提：青龙形态Ⅰ（逐级）<br> 价格：B+2000<br> 描述：升华青龙形态下，灵石的颜色变为金色，身上也出现金色的条纹。<br> 效果：你在变身后若进入青龙形态，会变为金色边框的蓝色升华青龙形态。<br> ——<br> 在升华青龙的形态下，除了保留青龙形态提供的一切效果外，你每轮第一次使用反射动作招架应对攻击无需保留移动动作，依旧可以进行招架。在使用这一动作进行招架时，还会如同已经移出攻击范围一样计算。</p><p>升华天马形态<br> 前提：天马形态ⅠⅠ（逐级）<br> 价格：B+2000<br> 描述：升华天马形态下，灵石的颜色变为金色，身上也出现金色的条纹。<br> 效果：你在变身后若进入天马形态，会变为金色边框的绿色升华天马形态。<br> ——<br> 在升华天马的形态下，除了保留天马形态提供的一切效果外，你具有的措手不及免疫能力提升至A级，天马形态提供的侦测范围改为敏感范围增加一倍。若你已具有天马形态中提及的侦测能力，则侦测能力等级提升至B级。<br> 由于主神的强化，你还会获得等同自身基础移动速度的飞行能力，机动性普通。</p><p>升华泰坦形态<br> 前提：泰坦形态Ⅰ（逐级）<br> 价格：B+4000<br> 描述：升华泰坦形态下，灵石的颜色变为金色，身上也出现金色的条纹。<br> 效果：你在变身后若进入泰坦形态，会变为金色边框的紫色升华泰坦形态。<br> ——<br> 在升华泰坦的形态下，除了保留泰坦形态提供的一切效果外，你额外获得基于天生防御的【适应】【超级坚韧】特性，同时额外获得2点异常点数医疗能力，医疗池24点。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',28)])])}const D=e(o,[["render",s]]);export{C as __pageData,D as default};
